import { Command } from 'commander';
import { resizeDir } from './resize.js';
import { loadConfig } from './config.js';
import { logger } from './logger.js';

export function run(argv) {
  const program = new Command();
  program
    .argument('<input>')
    .option('--width <n>', 'max width', '1200')
    .option('--format <fmt>', 'output format', 'webp')
    .option('--out <dir>', 'output dir', './dist')
    .action(async (input, opts) => {
      const cfg = loadConfig(opts);
      const n = await resizeDir(input, cfg);
      logger.info(`done: ${n} images`);
    });
  program.parse(argv);
}

import sharp from 'sharp';
import { readdir } from 'node:fs/promises';
import { encoderFor } from './formats.js';

export async function resizeDir(dir, cfg) {
  const files = await readdir(dir);
  let count = 0;
  for (const f of files) {
    const pipeline = sharp(`${dir}/${f}`).resize({ width: cfg.width });
    await encoderFor(cfg.format)(pipeline).toFile(`${cfg.out}/${f}`);
    count++;
  }
  return count;
}

export function encoderFor(fmt) {
  if (fmt === 'webp') return (p) => p.webp({ quality: 80 });
  if (fmt === 'png') return (p) => p.png({ compressionLevel: 9 });
  return (p) => p.jpeg({ quality: 82 });
}
